import { useEffect, useState } from "react";
import { Button } from "@/components/ui/button";
import { Checkbox } from "@/components/ui/checkbox";
import { Input } from "@/components/ui/input";
import { Label } from "@/components/ui/label";
import { useForm } from "@tanstack/react-form";
import { createFileRoute } from "@tanstack/react-router";
import { createServerFn } from "@tanstack/react-start";
import type { LeadSubmissionRequest } from "@workspace/api-client/public";
import {
  submitLeadPage,
  useGetPublicActionPageQueryOptions,
} from "@workspace/api-client/public";
import type { ActionPageDesignConfiguration } from "@workspace/api-client/types";

const submitLead = createServerFn({ method: "POST" }).handler(
  async ({ data }) => {
    return submitLeadPage(data);
  },
);

export const Route = createFileRoute("/lead/$slug/$token")({
  ssr: "data-only",
  component: RouteComponent,
  errorComponent: LeadErrorComponent,
  loader: async ({ context: { queryClient }, params: { slug, token } }) => {
    const options = useGetPublicActionPageQueryOptions({
      actionPageSlug: token,
      accountSlug: slug,
    });
    const actionPage = await queryClient.ensureQueryData(options);
    return { actionPage };
  },
});

// TODO: map the data to better variables first, or change this in the BE model
// itself
// TODO: looks like we don't use colors from designconfiguration, but we could
// here if we want to
const setTheme = (_designConfiguration: ActionPageDesignConfiguration) => {
  const colorMap = new Map<string, string>([
    [
      "--brand-primary-foreground",
      // default slate-700
      "oklch(37.2% 0.044 257.287)",
    ],
    ["--brand-primary", "oklch(100% 0 0)"],
    [
      "--brand-secondary-foreground",
      // default slate-700
      "oklch(37.2% 0.044 257.287)",
    ],
    ["--brand-secondary", "oklch(100% 0 0)"],
  ]);
  colorMap.forEach((value, key) => {
    document.documentElement.style.setProperty(key, value);
  });
};

const required = ({ value }: { value: string }) =>
  !value ? "Required" : undefined;

const isValidCallbackUrl = (callbackUrl: unknown): callbackUrl is string => {
  if (typeof callbackUrl !== "string") {
    return false;
  }

  const trimmed = callbackUrl.trim();
  if (!trimmed) {
    return false;
  }

  if (trimmed.startsWith("/")) {
    // Reject protocol-relative URLs like //example.com.
    return !trimmed.startsWith("//");
  }

  try {
    const parsedUrl = new URL(trimmed);
    return parsedUrl.protocol === "http:" || parsedUrl.protocol === "https:";
  } catch {
    return false;
  }
};

function RouteComponent() {
  const { actionPage } = Route.useLoaderData();
  const { slug, token } = Route.useParams();
  const [isPending, setIsPending] = useState(false);

  useEffect(() => {
    setTheme(actionPage.designConfiguration);
  }, [actionPage.designConfiguration]);

  const form = useForm({
    defaultValues: {
      email: "",
      emailOptIn: false,
      phoneOptIn: false,
      phone: "",
      firstName: "",
      lastName: "",
      address1: "",
      address2: "",
      city: "",
      state: "",
      postalCode: "",
      country: "",
    },
    onSubmit: async ({ value }) => {
      setIsPending(true);
      try {
        const response = await submitLead({
          data: {
            accountSlug: slug,
            actionPageSlug: token,
            email: value.email,
            firstName: value.firstName,
            lastName: value.lastName,
            phone: value.phone,
            addressAttributes: {
              line1: value.address1,
              line2: value.address2 || undefined,
              city: value.city,
              region: value.state || undefined,
              postalCode: value.postalCode,
              country: value.country,
            },
          },
        });

        if (isValidCallbackUrl(response.callbackUrl)) {
          // this is different from what it was in the old app
          //   the user can hit the back button to modify and submit the form
          //   again
          window.location.assign(response.callbackUrl);
        }
      } finally {
        setIsPending(false);
      }
    },
  });

  return (
    <div className="h-screen w-full space-y-6 bg-brand-primary p-6 text-brand-secondary-foreground sm:h-fit sm:max-w-lg sm:rounded-xl sm:p-12 sm:shadow-md">
      <h1 className="text-center text-brand-primary-foreground">
        {actionPage.headerTitleText}
      </h1>

      <p className="text-right text-muted-foreground text-xs">
        Already have an account? <a href="/login">Login</a>
      </p>
      {actionPage.description && (
